import{_ as a,o,c as r,a2 as t}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Introducción","description":"","frontmatter":{},"headers":[],"relativePath":"es/guide/introduction.md","filePath":"es/guide/introduction.md"}'),n={name:"es/guide/introduction.md"};function i(s,e,d,c,l,u){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="introduccion" tabindex="-1">Introducción <a class="header-anchor" href="#introduccion" aria-label="Permalink to &quot;Introducción&quot;">​</a></h1><h2 id="¿que-es-clearance" tabindex="-1">¿Qué es Clearance? <a class="header-anchor" href="#¿que-es-clearance" aria-label="Permalink to &quot;¿Qué es Clearance?&quot;">​</a></h2><p>Clearance es un panel de administración listo para usar en aplicaciones Laravel, construido sobre <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a>. Añade un panel Livewire 4 + Flux UI para gestionar permisos, roles, guards y configuración, además de una capa de autorización contextual y techos de rol - instalable con un solo comando artisan, sin alterar ninguna tabla de Spatie.</p><p>Clearance te ofrece:</p><ul><li><strong>Panel de administración</strong> para Permisos, Roles, Guards, Configuración y un Panel de Control - usa las rutas prediseñadas o incorpora cada componente Livewire individualmente.</li><li><strong>Autorización contextual</strong> - otorga un rol o permiso limitado a una instancia de modelo específica (una Tienda, un Tenant, un Proyecto), con <code>$user-&gt;canIn()</code>, las directivas Blade <code>@canin</code>/<code>@hasrolein</code>, y un <code>ContextService</code> para usar fuera del modelo User.</li><li><strong>Roles techo</strong> - un rol puede declarar un rol padre cuyo conjunto de permisos actúa como límite superior; un rol hijo nunca puede superar a su padre, algo que se aplica automáticamente en cada guardado.</li><li><strong>Permisos de escritura granulares</strong> - un permiso delegable <code>clearance-{section}-write</code> por cada sección del panel, para que puedas otorgar &quot;gestionar roles&quot; sin otorgar también &quot;gestionar configuración&quot;.</li><li><strong>Super Admin</strong> con un bypass de Gate global opcional, detección de alias para roles de tipo admin existentes, y promoción segura no destructiva.</li><li><strong>Módulo de Usuarios</strong> (opcional) - asigna roles de forma global o a un contexto específico, además de overrides de permisos por contexto, desde un panel por usuario.</li><li><strong>Panel de Configuración</strong> - nombre de visualización, descripción, icono SVG sanitizado y color por rol/guard; un rol predeterminado configurable con auto-asignación y asignación masiva.</li><li><strong>Gestión de Guards</strong> - guards respaldados por base de datos, inyectados en <code>auth.guards</code> al arrancar, restringidos a un conjunto de drivers en lista de permitidos.</li><li><strong>9 idiomas incluidos</strong> (ar, en, es, fr, hi, it, pt, ru, zh), con paridad de claves verificada.</li><li><strong>Puntos de extensión</strong> - el trait <code>HasClearance</code>, el trait <code>HasPermissionGroups</code>, el contrato <code>ClearanceContextable</code>, componentes Blade reutilizables.</li><li><strong>Sanitización de SVG</strong> - cada icono proporcionado por el usuario pasa por un sanitizador basado en lista de permitidos antes de almacenarse y también al renderizarse.</li><li><strong>Reforzado en seguridad</strong> - techos de escalada de privilegios en cada ruta que otorga permisos, overrides de contexto con criterio de denegación autoritaria, namespace <code>clearance-*</code> protegido. Consulta <a href="/clearance-docs/es/guide/security.html">Seguridad</a>.</li></ul><h2 id="relacion-con-spatie-laravel-permission" tabindex="-1">Relación con spatie/laravel-permission <a class="header-anchor" href="#relacion-con-spatie-laravel-permission" aria-label="Permalink to &quot;Relación con spatie/laravel-permission&quot;">​</a></h2><p>Clearance no reemplaza al paquete de permisos de Spatie - es una capa de UI y autorización sobre él. Los roles y permisos siguen siendo los modelos <code>Role</code> y <code>Permission</code> de Spatie, almacenados en las tablas <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> y <code>role_has_permissions</code> de Spatie. Clearance nunca altera esas tablas. Todo lo que Clearance añade - metadatos de visualización, alcance de rol, techos, asignaciones contextuales, overrides por contexto - vive en su propio conjunto de tablas <code>clr_*</code>. Consulta <a href="/clearance-docs/es/guide/architecture.html">Arquitectura</a> para el desglose completo.</p><h2 id="requisitos" tabindex="-1">Requisitos <a class="header-anchor" href="#requisitos" aria-label="Permalink to &quot;Requisitos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependencia</th><th>Versión</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="conceptos-clave" tabindex="-1">Conceptos clave <a class="header-anchor" href="#conceptos-clave" aria-label="Permalink to &quot;Conceptos clave&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concepto</th><th>Resumen</th></tr></thead><tbody><tr><td>Permission</td><td>Un permiso de Spatie que sigue la convención de nomenclatura <code>group-action</code> (p. ej. <code>orders-create</code>). Otorga una capacidad.</td></tr><tr><td>Alcance de rol</td><td>Todo rol es <code>global</code> (asignado directamente, se aplica en todas partes) o <code>contextual</code> (vinculado a tipos de modelo específicos, asignable solo dentro de una instancia de contexto).</td></tr><tr><td>Rol techo</td><td>Un rol puede declarar un rol padre cuyo conjunto de permisos es un límite superior - el hijo nunca puede superarlo.</td></tr><tr><td>Contexto</td><td>Una instancia de modelo (una Tienda, un Tenant, un Proyecto) a la que puede limitarse un rol o un override de permiso.</td></tr><tr><td>Override</td><td>Una concesión o denegación de permiso <code>forced_on</code>/<code>forced_off</code> por usuario y por contexto - una denegación siempre gana.</td></tr></tbody></table><p>Cada uno de estos conceptos tiene una página completa: <a href="/clearance-docs/es/features/permissions.html">Permisos</a>, <a href="/clearance-docs/es/features/roles.html">Roles</a>, <a href="/clearance-docs/es/features/contextual-authorization.html">Autorización Contextual</a>, <a href="/clearance-docs/es/features/users.html">Usuarios</a>, <a href="/clearance-docs/es/features/super-admin.html">Super Admin</a>.</p><h2 id="proximos-pasos" tabindex="-1">Próximos pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos pasos&quot;">​</a></h2><p>¿Listo para instalar Clearance? Continúa con la <a href="/clearance-docs/es/guide/installation.html">guía de Instalación</a>.</p>',14)])])}const g=a(n,[["render",i]]);export{m as __pageData,g as default};
